"""Проверка публичного API модуля file_discovery."""from __future__ import annotationsdef test_import_module_standalone() -> None:    """Публичный API модуля импортируется без зависимостей от остального проекта."""    from src.modules.file_discovery import (        DiscoveryConfig,        DiscoveredDocument,        DiscoveryService,        FileDiscoveryAccessDeniedError,        FileDiscoveryError,        FileDiscoveryHashIOError,        FileDiscoveryPathNotFoundError,        HashSidecarService,        SKIP_EXTENSIONS,    )    assert DiscoveryConfig is not None    assert DiscoveredDocument is not None    assert DiscoveryService is not None    assert HashSidecarService is not None    assert issubclass(FileDiscoveryPathNotFoundError, FileDiscoveryError)    assert issubclass(FileDiscoveryAccessDeniedError, FileDiscoveryError)    assert issubclass(FileDiscoveryHashIOError, FileDiscoveryError)    assert ".md5" in SKIP_EXTENSIONS